INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00289', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「古代希臘哲學家亞里斯多德說：『快樂就是生命的意義和目的，也是人類生存的總目標』； 還有一位奧妙的悲觀主義者，德國哲學家叔本華的一句智慧之言：『快樂乃是健康所開放的 花朵，而健康則從勤勞、節慾、衛生產生。』一點也不假，健康必須力求身心兩健，保養生 理的健康，必也同時保持心理的健全，才能整合身心兩者的愉快，延年益壽。」 根據上文，下列敘述適當的是：', '["生命的意義和目的，在於實踐自己的願望", "勤奮地工作，可以彰顯生命的意義和目的", "做好環境清潔，是讓自己獲得快樂的捷徑", "同時保持生理和心理健康，可以延年益壽 人生最大的快樂，來自於擁有樂觀與智慧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00290', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「『核心素養』是社會群體成員共有的知識、能力與態度，是全方位的素養；『專門素養』 是特定行業人員所具備的特定行業或專門職業的專門素養之知識、能力與態度。『核心素養』 主要目的是強調社會功能，以建立功能健全的社會；『專門素養』主要目的是強調個人具備 特定行業所需的素養，以加入特定專門職業團體，以協助個人獲得成功的生活。」 根據上文，下列選項何者對素養類別的判斷正確？', '["核心素養：開車時願意禮讓行人", "專門素養：能與他人溝通並互動", "核心素養：可以自行研發新產品", "專門素養：能成功行銷工商百貨 核心素養：開發水產養殖新方法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00291', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何人重視遊戲的教育價值，強調遊戲是兒童最自然的自我表現活動，也是教師用以宣洩兒童內在能力 的最好手段？', '["裴斯塔洛齊（J.H.Pestalozzi）", "赫爾巴特（J.F.Herbart）", "福祿貝爾（F.W.A.Froebel）", "洛克（J.Locke）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00292', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「教育歷程除其自身以外，沒有外在的教育目的，目的係存在於教育歷程之中。」此種教育目的觀係與下 列何人的主張最為契合？', '["尼爾（A.S.Neill）", "杜威（J.Dewey）", "加德納（H.Gardner）", "皮德思（R.S.Peters）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00293', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '在講解教育與文化的關係時，丙老師闡釋「教育是文化保存、傳遞與創造的歷程」，期勉同學承擔文化傳 承與創新的責任與使命。他強調教育的文化功能，係與下列何人的觀點相近？', '["斯普朗格（E.Spranger）", "斯賓賽（H.Spencer）", "赫欽斯（R.Hutchins）", "班托克（G.Bantock）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00294', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '上體育課時，甲老師認為體育訓練與體育教育沒有什麼不同，因此專注於學生對於體育技能的訓練與督 導，但乙老師認為依據皮德思（R.S.Peters）的說法，訓練是指在一個固定的情境裡，獲得合適的習慣反 應，但缺乏下列教育上的何種意義？', '["技能意義", "自願意義", "行動意義", "認知意義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00295', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '根據十二年國民基本教育課程綱要總綱，普通型高中的「校訂課程」不包括下列何者？', '["校訂必修課程", "彈性學習時間", "專業科目", "選修課程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00296', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「教育是傳道授業解惑的活動。」這是屬於教育下列何種性質的定義？', '["規範性", "功能性", "內涵性", "時代性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00297', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「強調全民教育機會均等，教育發展應兼顧個人與社會發展。」是屬於下列何種思想的主張？', '["唯實主義", "自然主義", "民主主義", "國家主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00298', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-113-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '「道德是人的第二生命。」這句話是屬於下列何種教育語言？', '["口號", "隱喻", "明喻", "理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:38+00:00", "source_pdf_sha1": "ae7d64956c07", "answer_pdf_sha1": "8515b075d174", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "504", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
